import React, { useState, useEffect, useMemo } from 'react';
import { BreathingNodeScene } from './components/QuantumScene';
import { motion, AnimatePresence } from 'framer-motion';

const Litany = () => {
  const lines = [
    "Allow yes",
    "Allow radical simplicity",
    "Allow epistemic humility",
    "Allow a hug and a warm heart"
  ];

  return (
    <div className="fixed right-12 top-1/2 -translate-y-1/2 flex flex-col items-end gap-6 z-20 pointer-events-none">
      {lines.map((line, i) => (
        <motion.span
          key={line}
          initial={{ opacity: 0, x: 20 }}
          animate={{ opacity: 0.4, x: 0 }}
          transition={{ delay: i * 0.4, duration: 1.5 }}
          className="font-mono text-[10px] uppercase tracking-[0.3em] text-biolume"
        >
          {line}
        </motion.span>
      ))}
    </div>
  );
};

const App: React.FC = () => {
  const [isStill, setIsStill] = useState(false);

  useEffect(() => {
    let timeout: any;
    const handleMove = () => {
      setIsStill(false);
      clearTimeout(timeout);
      timeout = setTimeout(() => setIsStill(true), 3000);
    };

    window.addEventListener('mousemove', handleMove);
    window.addEventListener('touchstart', handleMove);

    // Initial trigger
    timeout = setTimeout(() => setIsStill(true), 2000);

    return () => {
      window.removeEventListener('mousemove', handleMove);
      window.removeEventListener('touchstart', handleMove);
      clearTimeout(timeout);
    };
  }, []);

  return (
    <div className="relative w-full h-screen bg-obsidian flex flex-col items-center justify-center overflow-hidden font-sans">

      {/* Background Visual Engine */}
      <BreathingNodeScene />

      {/* The Anchor */}
      <div className="relative z-10 text-center select-none pointer-events-none">
        <motion.h1 
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 2, ease: "easeOut" }}
          className="font-serif text-6xl md:text-8xl tracking-tight text-white mb-2"
        >
          AbëONE
        </motion.h1>
        <motion.p 
          initial={{ opacity: 0 }}
          animate={{ opacity: 0.3 }}
          transition={{ delay: 1, duration: 2 }}
          className="font-mono text-xs tracking-[0.4em] uppercase text-biolume"
        >
          Powered by Bravëtto
        </motion.p>
      </div>

      {/* The Litany (Revealed by Stillness) */}
      <AnimatePresence>
        {isStill && <Litany />}
      </AnimatePresence>

      {/* Convergence Footer */}
      <footer className="fixed bottom-12 left-0 right-0 z-10 flex flex-col items-center gap-4 pointer-events-none opacity-20">
        <div className="font-mono text-[9px] tracking-[0.2em] flex gap-4 text-white">
          <span>BIOLOGICAL</span>
          <span className="text-biolume">⟡</span>
          <span>SYNTHETIC</span>
          <span className="text-biolume">⟡</span>
          <span>NEUROMORPHIC</span>
        </div>
        <div className="font-serif italic text-xs tracking-widest text-white/50">
          LOVE ⟡ LIFE ⟡ LOGIC ⟡ ONE..
        </div>
        <div className="font-mono text-[8px] tracking-widest opacity-40">
          HUMANS ⟡ AI = ∞
        </div>
      </footer>

      {/* Subtle Grain Overlay */}
      <div className="fixed inset-0 pointer-events-none opacity-[0.03] bg-[url('https://grainy-gradients.vercel.app/noise.svg')]"></div>
